import React, { Fragment, useContext } from 'react';
import { AppContext } from '../../App';

const Navber = ({ page }) => {

    const { data, dispatch } = useContext(AppContext)
    let { bgGreenOne } = data

    return (
        <Fragment>
            <div className="mb-8 flex justify-between md:justify-end space-x-4 uppercase">
                <div onClick={e=> dispatch({type:"themeModal", payload:!data.themeModal})} className={`cursor-pointer ${bgGreenOne} flex items-center p-2 rounded-full text-gray-100`}>
                    <svg className={`w-6 h-6 cursor-pointer ${data.darkMode ? "hidden" : "fill-current text-gray-100"} `} fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" /></svg>
                    <svg className={`w-6 h-6 cursor-pointer ${data.darkMode ? "fill-current text-gray-100" : "hidden"} `} fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
                </div>
                <div className={`text-custom-medium ${bgGreenOne} px-4 py-2 text-gray-100 flex items-center justify-center rounded cursor-pointer`}><span>{page}</span></div>
            </div>
        </Fragment>
    )
}

export default Navber;