import React, { Fragment, useState, useContext } from 'react';
import LinkdIn from '../img/LinkedIn.svg';
import Twitter from '../img/Twitter.svg';
import Gmail from '../img/Gmail.svg';
import Skype from '../img/Skype.svg';
import Github24 from '../img/Github24.svg';
import { AppContext } from '../../App';

const ContactMain = () => {

    const [message, setMessage] = useState(false)
    const { data } = useContext(AppContext)
    let { grayThree, grayOne, bgGreenOne } = data

    const handleGmailCopy = (e) => {
        e.preventDefault();
        navigator.clipboard.writeText('mahmudul.hasan.py@gmail.com')
        setMessage(true)
    }

    return (
        <Fragment>
	    	<div className="mt-20 md:mt-0 grid grid-cols-1 md:grid-cols-2 flex xl:space-x-4">
	    		<div className="grid grid-cols-2 col-span-1">
	    			<div className="col-span-1 flex flex-col justify-around items-center">
	    				<div className="lg:p-4 xl:p-6">
	    					<a href="https://bd.linkedin.com/in/hasan-py"> <img className="contact-icon hover:bg-gray-300 rounded-full p-4 cursor-pointer" src={LinkdIn} alt="LinkdIn"/> </a>
	    				</div>
	    				<div className="lg:p-4 xl:p-6">
	    					<img onClick={e=> handleGmailCopy(e)} className="contact-icon hover:bg-gray-300 rounded-full p-4 cursor-pointer" src={Gmail} alt="Gmail"/>
	    				</div>
	    			</div>
	    			<div className="col-span-1 flex flex-col justify-around items-center">
	    				<div className="lg:p-4 xl:p-6">
	    					<a href="https://twitter.com/hasan_py"> <img className="contact-icon hover:bg-gray-300 rounded-full p-4 cursor-pointer" src={Twitter} alt="Twitter"/> </a>
	    				</div>
	    				<div className="lg:p-4 xl:p-6">
	    					<a href="https://join.skype.com/invite/D4JlfeOPY4rj"> <img className="contact-icon hover:bg-gray-300 rounded-full p-4 cursor-pointer" src={Skype} alt="Skype"/> </a>
	    				</div>
	    			</div>
	    		</div>
	    		<div className="col-span-1 px-6 flex flex-col justify-center">
	    			<div className={`${data.darkMode ? grayOne : grayThree} text-center py-2`}>
	    				Feel free to contact with us
	    			</div>
	    			<a href="https://www.fiverr.com/hasan_py">
		    			<div className="text-center cursor-pointer text-white shadow-lg py-2 rounded bg-green-500">
		    				 Order on Fiverr
		    			</div>
	    			</a>
	    			<a className="mt-2" href="https://www.github.com/hasan-py">
		    			<div className="flex items-center justify-center text-center cursor-pointer text-white shadow-lg py-2 rounded bg-black">
		    				<img src={Github24} alt="github"/>
		    				<span className="mx-2">
		    					Experience 
		    				</span>
		    			</div>
	    			</a>
	    		</div>
	    	</div>
	    	{
	    		message
		    	? <div onClick={e=> setMessage(false)} className={`flex md:space-x-2 items-center rounded fixed top-0 right-0 my-20 md:my-16 mx-4 transition-all duration-300 ease-in ${bgGreenOne} text-white py-2 px-4 text-xl font-weight-light shadow-lg cursor-pointer`}>
		    		<span>Gmail copy to clipboard</span>
		    		<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
		    	 </div>
	    		: ""
	    	}
    	</Fragment>
    )
}

export default ContactMain;