export const appState = {
    primaryColor: localStorage.getItem("primaryColor") ? JSON.parse(localStorage.getItem("primaryColor")) : "green",
    darkMode: localStorage.getItem("darkmode") ? JSON.parse(localStorage.getItem("darkmode")) : false,
    loading: false,
    projectList: null,
    themeModal: false,

    /* Primary Color */
    greenOne: localStorage.getItem("greenOne") ? JSON.parse(localStorage.getItem("greenOne")) : "text-green-600",
    borderGreenOne: localStorage.getItem("borderGreenOne") ? JSON.parse(localStorage.getItem("borderGreenOne")) : "border-green-600",
    bgGreenTwo: localStorage.getItem("bgGreenTwo") ? JSON.parse(localStorage.getItem("bgGreenTwo")) : "bg-green-200",
    bgGreenOne: localStorage.getItem("bgGreenOne") ? JSON.parse(localStorage.getItem("bgGreenOne")) : "bg-green-600",

    /* Text Color */
    grayOne: "text-gray-100",
    grayTwo: "text-gray-900",
    grayThree: "text-gray-800",
    white: "text-white",

    /* Backgound Color */
    bgGrayOne: "bg-gray-100",
    bgGrayTwo: "bg-gray-900",
    bgGrayThree: "bg-gray-800",

}


export const appReducer = (state, action) => {
    switch (action.type) {
        case 'darkMode':
            if (state.darkMode) {
                localStorage.removeItem("darkmode")
                localStorage.setItem("darkmode", JSON.stringify(false))
            } else {
                localStorage.removeItem("darkmode")
                localStorage.setItem("darkmode", JSON.stringify(true))
            }
            return {
                ...state,
                darkMode: action.payload
            }
        case 'loading':
            return {
                ...state,
                loading: action.payload
            }
        case 'projectList':
            return {
                ...state,
                projectList: action.payload
            }
        case 'themeModal':
            return {
                ...state,
                themeModal: action.payload
            }
        case 'primaryColor':
            localStorage.setItem("primaryColor", JSON.stringify(action.payload))
            localStorage.setItem("greenOne", JSON.stringify(`text-${action.payload}-600`))
            localStorage.setItem("borderGreenOne", JSON.stringify(`border-${action.payload}-600`))
            localStorage.setItem("bgGreenTwo", JSON.stringify(`bg-${action.payload}-200`))
            localStorage.setItem("bgGreenOne", JSON.stringify(`bg-${action.payload}-600`))

            return {
                ...state,
                primaryColor: action.payload,
                greenOne: `text-${action.payload}-600`,
                borderGreenOne: `border-${action.payload}-600`,
                bgGreenTwo: `bg-${action.payload}-200`,
                bgGreenOne: `bg-${action.payload}-600`,
            }
        default:
            return state
    }
}