import React, { useContext } from 'react';
import { AppContext } from '../../App';

const SettingTheme = (props) => {

    const { data, dispatch } = useContext(AppContext);
    let { bgGrayTwo, bgGrayOne, grayThree, grayOne, greenOne } = data

    return (
        <div>
            {/* Black Overlay */}
            <div onClick={e=> dispatch({type:"themeModal", payload:false})} className={`${data.themeModal ? "" : "hidden"} fixed top-0 left-0 z-30 w-full h-full bg-black opacity-50`} />
            {/* End Black Overlay */}

            {/* Modal Start */}
            <div className={`${data.themeModal ? "" : "hidden"} rounded fixed inset-0 m-4 flex items-center z-30 justify-center`}>
              <div className={`relative ${data.darkMode ? bgGrayTwo : bgGrayOne } rounded w-full md:w-9/12 xl:w-6/12 shadow-lg flex flex-col items-center space-y-4 overflow-y-auto px-4 py-4 md:px-8`}>
                <div className="flex items-center justify-between w-full pt-4">
                  <span className={`${data.darkMode ? grayOne : grayThree } tracking-wide text-left font-semibold`}>Change Theme</span>
                  {/* Close Modal */}
                  <span onClick={e=> dispatch({type:"themeModal", payload:false})} className={`cursor-pointer ${greenOne} py-2 px-2 rounded-full`}><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></span>
                </div>
                <div className={`${data.darkMode ? bgGrayOne : bgGrayTwo} rounded w-full p-1`}>
                    <div className="flex items-center w-full flex items-center justify-center">
                        <div onClick={e=> dispatch({type:"darkMode", payload:false})} className={`cursor-pointer ${data.darkMode ? bgGrayTwo+" "+grayOne : bgGrayOne+" "+grayThree} py-2 rounded px-4 w-1/2 flex items-center justify-center`}>
                            <span>Default</span>
                            <span className={`${data.darkMode ? "hidden" : grayThree} `}>
                                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                            </span>
                        </div>
                        <div onClick={e=> dispatch({type:"darkMode", payload:true})} className={`cursor-pointer ${data.darkMode ? bgGrayOne+" "+grayThree : bgGrayTwo+" "+grayOne} py-2 bg-gray-100 rounded px-4 w-1/2 flex items-center justify-center`}>
                            <span>Dark</span>
                            <span className={`${data.darkMode ?  grayThree: "hidden" } `}>
                                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                            </span>
                        </div>
                    </div>
                </div>
                <div className="w-full">
                    <div className="flex items-center justify-around w-full">
                        <span onClick={e=> dispatch({type:"primaryColor", payload:"orange"})} className="cursor-pointer block w-12 h-12 rounded-full bg-orange-600 flex items-center justify-center">
                            {
                                data.primaryColor === 'orange'
                                && <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                            }
                        </span>
                        <span onClick={e=> dispatch({type:"primaryColor", payload:"green"})} className="cursor-pointer block w-12 h-12 rounded-full bg-green-600 flex items-center justify-center">
                            {
                                data.primaryColor === 'green'
                                && <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                            }
                        </span>
                        <span onClick={e=> dispatch({type:"primaryColor", payload:"purple"})} className="cursor-pointer block w-12 h-12 rounded-full bg-purple-600 flex items-center justify-center">
                            {
                                data.primaryColor === 'purple'
                                && <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                            }
                        </span>
                        <span onClick={e=> dispatch({type:"primaryColor", payload:"pink"})} className="cursor-pointer block w-12 h-12 rounded-full bg-pink-600 flex items-center justify-center">
                            {
                                data.primaryColor === 'pink'
                                && <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                            }
                        </span>
                    </div>
                </div>
              </div>
            </div>
        </div>
    )
}

export default SettingTheme;